import{c as a,Q as t,j as s,m as n}from"./chunks/framework.CKo_DbFQ.js";const m=JSON.parse('{"title":"OpenBao and cert-manager","description":"","frontmatter":{},"headers":[],"relativePath":"showcases/openbao.md","filePath":"showcases/openbao.md","lastUpdated":1781113651000}'),o={name:"showcases/openbao.md"};function i(r,e,l,p,h,c){return t(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="openbao-and-cert-manager" tabindex="-1">OpenBao and cert-manager <a class="header-anchor" href="#openbao-and-cert-manager" aria-label="Permalink to &quot;OpenBao and cert-manager&quot;">​</a></h1><p><a href="https://openbao.org" target="_blank" rel="noreferrer">OpenBao</a> is an open-source fork of HashiCorp Vault, maintained by the Linux Foundation after Vault&#39;s license change to BSL. The API and CLI are fully compatible — the only visible difference is the <code>bao</code> command instead of <code>vault</code>.</p><h3 id="precondition" tabindex="-1">Precondition <a class="header-anchor" href="#precondition" aria-label="Permalink to &quot;Precondition&quot;">​</a></h3><p>Cluster has to be deployed with the <em>httpbin</em> sample. Otherwise this demo wouldn&#39;t work.</p><h3 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h3><p>You can start the installation script of OpenBao and cert-manager with the included shell script. httpbin and the OpenBao UI are exposed via Kong Gateway (Gateway API / <code>HTTPRoute</code>), which is the cluster&#39;s default ingress.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> examples/openbao</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup.sh</span></span></code></pre></div><p>The following components are installed with the <em>setup.sh</em>:</p><ul><li>OpenBao - HELM Chart (namespace: <code>openbao</code>)</li><li>Configuration of OpenBao server <ul><li>Configure key-share and key-threshold</li><li>Unseal OpenBao server</li><li>Enable PKI, import Root CA</li><li>Create role to issue certificates for domain <em>example.com</em></li><li>Enable Kubernetes auth, add policy for service account <em>issuer</em></li></ul></li><li>Install cert-manager - HELM Chart</li><li>Create service account <em>issuer</em> in cert-manager namespace</li><li>Create <code>ClusterIssuer</code> named <code>openbao-issuer</code> (connection to OpenBao)</li><li>Create certificate for <em>www.example.com</em> — places K8s secret with key, ca and cert in demo namespace</li><li>Configure Kong Gateway TLS listener and <code>HTTPRoute</code>s in demo/kong namespace to secure httpbin and the OpenBao UI with an OpenBao-signed wildcard certificate</li></ul><h3 id="test-ingress" tabindex="-1">Test Ingress <a class="header-anchor" href="#test-ingress" aria-label="Permalink to &quot;Test Ingress&quot;">​</a></h3><p>The <em>httpbin</em> <code>HTTPRoute</code> is added by this sample deployment. You can test the Ingress by adding the following entries to your <em>/etc/hosts</em> file:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Append to /etc/hosts</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[...]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">127.0.0.1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">		httpbin.example.com</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">127.0.0.1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">		openbao.example.com</span></span></code></pre></div><p>After that you can open <em>httpbin</em> with the URL: <a href="https://httpbin.example.com:8081" target="_blank" rel="noreferrer">https://httpbin.example.com:8081</a>. When you have added the Root CA to your system Truststore, or your browser the connection should be secured correctly. You can find the Root CA certificate under: <code>examples/openbao/root-certs/rootCACert.pem</code>.</p><h3 id="show-openbao-ui" tabindex="-1">Show OpenBao UI <a class="header-anchor" href="#show-openbao-ui" aria-label="Permalink to &quot;Show OpenBao UI&quot;">​</a></h3><p>The OpenBao UI is exposed via Ingress, you can open it in a browser: <a href="https://openbao.example.com:8081/ui" target="_blank" rel="noreferrer">https://openbao.example.com:8081/ui</a></p>`,15)])])}const u=a(o,[["render",i]]);export{m as __pageData,u as default};
